# 统计A列每个值在C列中出现的次数
count_dict = {}

# 遍历所有行（行索引从0开始）
for row_idx in range(len(_table)):
    a_value = _table[row_idx][0]  # A列的值
    c_value = _table[row_idx][2]  # C列的值（索引2表示第3列）

    # 检查C列是否包含A列的值
    if a_value in str(c_value):
        if a_value in count_dict:
            count_dict[a_value] += 1
        else:
            count_dict[a_value] = 1

_result = count_dict
